from functools import lru_cache
import outlines

@lru_cache(maxsize=32)
def get_generator(schema_class):
    """Compile and cache a constrained generator for a given schema class."""
    return outlines.generate.json(MODEL, schema_class)

# At request time — cache hit, no recompilation
generator = get_generator(ExtractedPerson)
result = generator(prompt)
